package com.example.loggingapi.controller;

import com.example.loggingapi.model.ApiResponse;
import com.example.loggingapi.service.MessageService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api")
public class MessageController {

    private static final Logger logger = LoggerFactory.getLogger(MessageController.class);

    private final MessageService messageService;

    public MessageController(MessageService messageService) {
        this.messageService = messageService;
    }

    @GetMapping("/hello")
    public ApiResponse hello() {
        logger.info("Received request for hello endpoint");
        String message = messageService.getHelloMessage();
        logger.info("Successfully processed hello endpoint");
        return new ApiResponse("success", message);
    }

    @PostMapping("/echo")
    public ApiResponse echo(@RequestBody String payload) {
        logger.info("Received request for echo endpoint");
        String response = messageService.echo(payload);
        logger.info("Successfully processed echo endpoint");
        return new ApiResponse("success", response);
    }
}

